      {:ok, client} ->
        case AgentLoop.MCPClient.discover_tools(client) do
          {:ok, tools, client} ->
            tool_map = Map.new(tools, fn t -> {t["name"], name} end)
            mgr = %{mgr | servers: Map.put(mgr.servers, name, client),
                          tools: Map.merge(mgr.tools, tool_map)}
            {:ok, mgr}
          {:error, reason} -> {:error, reason}
        end
      {:error, reason} -> {:error, reason}
